function computeSnapshotDeltas(prevSnapshot, currSnapshot) {
  if (!prevSnapshot) return null;
  const prevHash = prevSnapshot.competitorHash;
  const currHash = currSnapshot.competitorHash;
  const competitorHashMatch = prevHash === currHash;
  if (!competitorHashMatch) return null;
  const prevSignals = parseJsonSafe2(prevSnapshot.signalData, []);
  const prevIntents = parseJsonSafe2(prevSnapshot.intentData, []);
  const prevTrajectory = parseJsonSafe2(prevSnapshot.trajectoryData, {});
  const prevDominance = parseJsonSafe2(prevSnapshot.dominanceData, []);
  const currSignals = currSnapshot.signalData;
  const currIntents = currSnapshot.intentData;
  const currTrajectory = currSnapshot.trajectoryData;
  const currDominance = currSnapshot.dominanceData;
  const signalDeltas = [];
  const signalFields = [
    "postingFrequencyTrend",
    "engagementVolatility",
    "ctaIntensityShift",
    "offerLanguageChange",
    "hashtagDriftScore",
    "bioModificationFrequency",
    "sentimentDrift",
    "reviewVelocityChange",
    "contentExperimentRate"
  ];
  for (const curr of currSignals) {
    const prev = prevSignals.find((p) => p.competitorId === curr.competitorId);
    if (!prev) continue;
    for (const field of signalFields) {
      const prevVal = prev.signals?.[field] ?? 0;
      const currVal = curr.signals?.[field] ?? 0;
      const delta = currVal - prevVal;
      if (Math.abs(delta) > 1e-3) {
        signalDeltas.push({
          competitorId: curr.competitorId,
          competitorName: curr.competitorName,
          signalField: field,
          previous: prevVal,
          current: currVal,
          delta
        });
      }
    }
  }
  const intentChanges = [];
  for (const curr of currIntents) {
    const prev = prevIntents.find((p) => p.competitorId === curr.competitorId);
    if (!prev) continue;
    intentChanges.push({
      competitorId: curr.competitorId,
      competitorName: curr.competitorName,
      previousIntent: prev.intentCategory,
      currentIntent: curr.intentCategory,
      changed: prev.intentCategory !== curr.intentCategory
    });
  }
  const trajectoryFields = [
    "marketHeatingIndex",
    "narrativeConvergenceScore",
    "offerCompressionIndex",
    "angleSaturationLevel",
    "revivalPotential"
  ];
  const trajectoryDeltas = [];
  for (const field of trajectoryFields) {
    const prevVal = prevTrajectory[field] ?? 0;
    const currVal = currTrajectory[field] ?? 0;
    const delta = currVal - prevVal;
    if (Math.abs(delta) > 1e-3) {
      trajectoryDeltas.push({ field, previous: prevVal, current: currVal, delta });
    }
  }
  const dominanceChanges = [];
  for (const curr of currDominance) {
    const prev = prevDominance.find((p) => p.competitorId === curr.competitorId);
    if (!prev) continue;
    const scoreDelta = (curr.dominanceScore ?? 0) - (prev.dominanceScore ?? 0);
    dominanceChanges.push({
      competitorId: curr.competitorId,
      competitorName: curr.competitorName,
      previousScore: prev.dominanceScore ?? 0,
      currentScore: curr.dominanceScore ?? 0,
      previousLevel: prev.dominanceLevel ?? "UNKNOWN",
      currentLevel: curr.dominanceLevel ?? "UNKNOWN",
      scoreDelta,
      levelChanged: prev.dominanceLevel !== curr.dominanceLevel
    });
  }
  const hasMeaningfulChanges = signalDeltas.length > 0 || intentChanges.some((c) => c.changed) || trajectoryDeltas.length > 0 || dominanceChanges.some((c) => c.levelChanged || Math.abs(c.scoreDelta) >= 1);
  return {
    signalDeltas,
    intentChanges,
    trajectoryDeltas,
    dominanceChanges,
    competitorHashMatch,
    hasMeaningfulChanges
  };
}
