// server/autopilot-routes.ts
init_db();
init_schema();
init_audit();
init_campaign_routes();
init_plan_constants();
import { Router } from "express";
import { eq as eq13, and as and11, desc as desc12, sql as sql8, gte as gte4 } from "drizzle-orm";

// server/confidence.ts
init_db();
init_schema();
import { eq as eq12, sql as sql7, desc as desc11 } from "drizzle-orm";
function calculateConfidence(params) {
  let score = 100;
  let volatilityPenalty = 0;
  const volRatio = params.volatilityThreshold > 0 ? params.volatilityIndex / params.volatilityThreshold : 0;
  if (volRatio > 1) {
    volatilityPenalty = 20;
  } else if (volRatio > 0.7) {
    volatilityPenalty = 10;
  } else if (volRatio > 0.4) {
    volatilityPenalty = 5;
  }
  let successRatePenalty = 0;
  if (params.totalDecisions >= 5) {
    if (params.decisionSuccessRate < 30) {
      successRatePenalty = 30;
    } else if (params.decisionSuccessRate < 50) {
      successRatePenalty = 20;
    } else if (params.decisionSuccessRate < 70) {
      successRatePenalty = 10;
    }
  }
  let driftPenalty = 0;
  if (params.driftFlag) {
    driftPenalty = 15;
  }
  let guardrailPenalty = Math.min(params.guardrailTriggers24h * 5, 20);
  score -= volatilityPenalty;
  score -= successRatePenalty;
  score -= driftPenalty;
  score -= guardrailPenalty;
  if (params.currentState === "SAFE_MODE") {
    score = Math.min(score, 40);
  }
  score = Math.max(score, 10);
  score = Math.min(score, 100);
  let status;
  if (score >= 80) {
    status = "Stable";
  } else if (score >= 60) {
    status = "Caution";
  } else {
    status = "Unstable";
  }
  return {
    score,
    status,
    inputs: {
      volatilityPenalty,
      successRatePenalty,
      driftPenalty,
      guardrailPenalty
    }
  };
}
async function computeDecisionSuccessRate(accountId) {
  const outcomes = await db.select({
    outcome: decisionOutcomes.outcome
  }).from(decisionOutcomes).where(eq12(decisionOutcomes.accountId, accountId)).orderBy(desc11(decisionOutcomes.evaluatedAt)).limit(20);
  const evaluated = outcomes.filter((o) => o.outcome !== null && o.outcome !== void 0);
  if (evaluated.length === 0) {
    return { successRate: 100, total: 0 };
  }
  const successes = evaluated.filter((o) => o.outcome === "success").length;
  return {
    successRate: successes / evaluated.length * 100,
    total: evaluated.length
  };
}
async function getLast2Outcomes(accountId) {
  const outcomes = await db.select({
    outcome: decisionOutcomes.outcome
  }).from(decisionOutcomes).where(
    sql7`${decisionOutcomes.accountId} = ${accountId} AND ${decisionOutcomes.outcome} IS NOT NULL`
  ).orderBy(desc11(decisionOutcomes.evaluatedAt)).limit(2);
  return outcomes.map((o) => o.outcome || "").filter(Boolean);
}
function checkSafeModeExitConditions(params) {
  const reasons = [];
  if (params.volatilityIndex >= params.volatilityThreshold) {
    reasons.push(`Volatility ${params.volatilityIndex.toFixed(3)} still above threshold ${params.volatilityThreshold}`);
  }
  if (params.guardrailTriggers24h > 0) {
    reasons.push(`${params.guardrailTriggers24h} guardrail trigger(s) in last 24h`);
  }
  if (params.driftFlag) {
    reasons.push("Sustained drift still detected");
  }
  const hasFailures = params.last2Outcomes.some((o) => o === "failure");
  if (params.last2Outcomes.length >= 2 && hasFailures) {
    reasons.push("Recent decision outcomes include failures");
  } else if (params.last2Outcomes.length < 2) {
  }
  return {
    canExit: reasons.length === 0,
    reasons
  };
}

