var UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
function verifySnapshotIntegrity(snapshot, expectedVersion, campaignId) {
  const failures = [];
  if (!snapshot) {
    return { valid: false, failures: ["snapshot is null or undefined"] };
  }
  if (!snapshot.id || typeof snapshot.id !== "string" || !UUID_REGEX.test(snapshot.id)) {
    failures.push(`invalid snapshot.id: ${snapshot.id}`);
  }
  if (!snapshot.createdAt) {
    failures.push("missing snapshot.createdAt");
  } else {
    const ts = new Date(snapshot.createdAt).getTime();
    if (isNaN(ts)) {
      failures.push(`invalid snapshot.createdAt: ${snapshot.createdAt}`);
    }
  }
  if (!snapshot.campaignId || snapshot.campaignId !== campaignId) {
    failures.push(`campaignId mismatch: snapshot=${snapshot.campaignId} expected=${campaignId}`);
  }
  const snapshotVersion2 = snapshot.analysisVersion ?? snapshot.version ?? 0;
  if (snapshotVersion2 !== expectedVersion) {
    failures.push(`version mismatch: snapshot=${snapshotVersion2} expected=${expectedVersion}`);
  }
  const hasOutput = !!(snapshot.analysisOutput || snapshot.output || snapshot.signalData || snapshot.confidenceData || snapshot.marketState);
  if (!hasOutput) {
    failures.push("output payload missing or empty");
  }
  return { valid: failures.length === 0, failures };
}
function getEngineReadinessState(snapshot, campaignId, expectedVersion = ENGINE_VERSION, freshnessThresholdDays = MI_CONFIDENCE.FRESHNESS_HARD_GATE_DAYS) {
  const diagnostics = {
    snapshotFound: false,
    snapshotId: null,
    campaignIdMatch: false,
    versionMatch: false,
    freshnessValid: false,
    freshnessDays: null,
    integrityValid: false,
    integrityFailures: [],
    engineState: "BLOCKED"
  };
  if (!snapshot) {
    diagnostics.engineState = "REFRESH_REQUIRED";
    logDiagnostics("MI", diagnostics);
    return { state: "REFRESH_REQUIRED", diagnostics, reason: "No snapshot found" };
  }
  diagnostics.snapshotFound = true;
  diagnostics.snapshotId = snapshot.id || null;
  const freshnessMetadata = buildFreshnessMetadata(snapshot);
  diagnostics.freshnessClass = freshnessMetadata.freshnessClass;
  diagnostics.stalenessCoefficient = freshnessMetadata.stalenessCoefficient;
  diagnostics.trustScore = freshnessMetadata.trustScore;
  diagnostics.schemaCompatible = freshnessMetadata.schemaCompatible;
  diagnostics.schemaVersion = freshnessMetadata.schemaVersion;
  diagnostics.snapshotSchemaVersion = freshnessMetadata.snapshotVersion;
  logFreshnessTraceability("MI", snapshot, freshnessMetadata);
  const integrity = verifySnapshotIntegrity(snapshot, expectedVersion, campaignId);
  diagnostics.integrityValid = integrity.valid;
  diagnostics.integrityFailures = integrity.failures;
  diagnostics.campaignIdMatch = snapshot.campaignId === campaignId;
  const snapshotVersion2 = snapshot.analysisVersion ?? snapshot.version ?? 0;
  diagnostics.versionMatch = snapshotVersion2 === expectedVersion;
  if (!integrity.valid) {
    const hasVersionMismatch = integrity.failures.some((f) => f.includes("version mismatch"));
    const hasCampaignMismatch = integrity.failures.some((f) => f.includes("campaignId mismatch"));
    if (hasVersionMismatch || hasCampaignMismatch) {
      diagnostics.engineState = "REFRESH_REQUIRED";
      logDiagnostics("MI", diagnostics);
      return { state: "REFRESH_REQUIRED", diagnostics, reason: `Integrity failed: ${integrity.failures.join("; ")}`, freshnessMetadata };
    }
    diagnostics.engineState = "BLOCKED";
    logDiagnostics("MI", diagnostics);
    return { state: "BLOCKED", diagnostics, reason: `Integrity failed: ${integrity.failures.join("; ")}`, freshnessMetadata };
  }
  const freshnessDays = snapshot.dataFreshnessDays ?? null;
  diagnostics.freshnessDays = freshnessDays;
  if (freshnessDays !== null && freshnessDays > freshnessThresholdDays) {
    diagnostics.freshnessValid = false;
    diagnostics.engineState = "REFRESH_REQUIRED";
    logDiagnostics("MI", diagnostics);
    return { state: "REFRESH_REQUIRED", diagnostics, reason: `Data stale: ${freshnessDays}d exceeds ${freshnessThresholdDays}d threshold`, freshnessMetadata };
  }
  diagnostics.freshnessValid = true;
  if (!freshnessMetadata.schemaCompatible) {
    diagnostics.engineState = "BLOCKED";
    logDiagnostics("MI", diagnostics);
    if (snapshot.id && snapshot.status !== "INCOMPATIBLE") {
      db.update(miSnapshots).set({ status: "INCOMPATIBLE" }).where(and21(eq32(miSnapshots.id, snapshot.id), eq32(miSnapshots.status, snapshot.status))).then(() => console.log(`[MI] SCHEMA_GUARD | snapshot=${snapshot.id.slice(0, 8)} | status persisted as INCOMPATIBLE (v${freshnessMetadata.snapshotVersion} != v${freshnessMetadata.schemaVersion})`)).catch((err) => console.error(`[MI] SCHEMA_GUARD | failed to persist INCOMPATIBLE: ${err.message}`));
    }
    return {
      state: "BLOCKED",
      diagnostics,
      reason: `Snapshot schema incompatible with current engine (v${freshnessMetadata.snapshotVersion} vs v${freshnessMetadata.schemaVersion}). Re-run analysis.`,
      freshnessMetadata
    };
  }
  if (freshnessMetadata.freshnessClass === "NEEDS_REFRESH") {
    diagnostics.engineState = "REFRESH_REQUIRED";
    logDiagnostics("MI", diagnostics);
    return {
      state: "REFRESH_REQUIRED",
      diagnostics,
      reason: `Data is ${Math.round(freshnessMetadata.ageInDays)}d old (max 7d for strategy). Re-run analysis.`,
      freshnessMetadata
    };
  }
  diagnostics.engineState = "READY";
  logDiagnostics("MI", diagnostics);
  return { state: "READY", diagnostics, freshnessMetadata };
}
function logDiagnostics(engineName, diagnostics) {
  console.log(`[${engineName}] Engine Status: snapshotFound=${diagnostics.snapshotFound} | snapshotId=${diagnostics.snapshotId?.slice(0, 8) || "N/A"} | campaignMatch=${diagnostics.campaignIdMatch} | versionMatch=${diagnostics.versionMatch} | freshnessDays=${diagnostics.freshnessDays ?? "N/A"} | freshnessValid=${diagnostics.freshnessValid} | integrityValid=${diagnostics.integrityValid} | state=${diagnostics.engineState}`);
  if (diagnostics.integrityFailures.length > 0) {
    console.log(`[${engineName}] Integrity failures: ${diagnostics.integrityFailures.join(", ")}`);
  }
}
async function invalidateStaleSnapshots() {
  console.log(`[MIv3] ENGINE_VERSION_CHECK | currentVersion=${ENGINE_VERSION} | action=startup_audit`);
  try {
    const activeSessions2 = await db.select({ campaignId: miSnapshots.campaignId }).from(miSnapshots).where(inArray8(miSnapshots.status, ["COMPLETE", "PARTIAL"]));
    const activeCampaignIds = new Set(activeSessions2.map((s) => s.campaignId));
    const staleSnapshots = await db.select({ id: miSnapshots.id, campaignId: miSnapshots.campaignId }).from(miSnapshots).where(eq32(miSnapshots.status, "STALE"));
    let recoveredCount = 0;
    let skippedCount = 0;
    for (const stale of staleSnapshots) {
      if (activeCampaignIds.has(stale.campaignId)) {
        skippedCount++;
        continue;
      }
      await db.update(miSnapshots).set({ status: "COMPLETE" }).where(and21(eq32(miSnapshots.id, stale.id), eq32(miSnapshots.status, "STALE")));
      recoveredCount++;
    }
    if (recoveredCount > 0 || skippedCount > 0) {
      console.log(`[MIv3] STALE_RECOVERY | recovered=${recoveredCount} | skipped=${skippedCount} (active session exists)`);
    }
    const oldVersionSnapshots = await db.select({ id: miSnapshots.id, analysisVersion: miSnapshots.analysisVersion }).from(miSnapshots).where(ne3(miSnapshots.analysisVersion, ENGINE_VERSION));
    const staleCount = oldVersionSnapshots.length;
    if (staleCount > 0) {
      console.log(`[MIv3] STARTUP_AUDIT_COMPLETE | outdatedSnapshots=${staleCount} | currentVersion=${ENGINE_VERSION} | action=SOFT_FLAG (snapshots preserved, version noted for downstream)`);
    } else {
      console.log(`[MIv3] STARTUP_AUDIT_COMPLETE | outdatedSnapshots=0 | allSnapshotsCurrentVersion=${ENGINE_VERSION}`);
    }
    return { invalidatedCount: 0 };
  } catch (error) {
    console.error(`[MIv3] STARTUP_AUDIT_ERROR | version=${ENGINE_VERSION} | error=${error}`);
    return { invalidatedCount: 0 };
  }
}

// server/market-intelligence-v3/routes.ts
init_constants();
var ALLOWED_MODES = ["overview", "dominance", "threats", "history"];
function enforceEngineWhitelist(req) {
  const body = req.body || {};
  const engineRef = body.engine || body.engineName || body.orchestrator;
  if (engineRef) {
    rejectBlockedEngine(engineRef, req.originalUrl);
  }
}
function registerMIv3Routes(app2) {
  app2.post("/api/ci/mi-v3/analyze", requireCampaign, async (req, res) => {
    try {
      enforceEngineWhitelist(req);
      validateEngineIsolation("MARKET_INTELLIGENCE_V3");
      const accountId = req.body.accountId || "default";
      const campaignId = req.body.campaignId;
      const mode = req.body.mode || "overview";
      const forceRefresh = req.body.forceRefresh === true;
      const validationSessionId = req.body.validationSessionId;
      if (!campaignId) {
        return res.status(422).json({ error: "campaignId is required" });
      }
      const sessionCheck = checkValidationSession(validationSessionId, "market-intelligence-v3", campaignId);
      if (!sessionCheck.allowed) {
        return res.status(429).json({
          error: "REVALIDATION_LOOP_BLOCKED",
          message: sessionCheck.warning
        });
      }
      if (!ALLOWED_MODES.includes(mode)) {
        return res.status(400).json({ error: `Invalid mode: ${mode}. Allowed: ${ALLOWED_MODES.join(", ")}` });
      }
      console.log(`[MIv3-Route] POST /api/ci/mi-v3/analyze | mode=${mode} | accountId=${accountId} | campaignId=${campaignId}`);
      const goalMode = req.body.goalMode === "REACH_MODE" ? "REACH_MODE" : "STRATEGY_MODE";
      const result = await MarketIntelligenceV3.run(mode, accountId, campaignId, forceRefresh, goalMode);
      if (result.signalDiagnostics) {
        console.log(`[MIv3-Route] SignalDiagnostics | posts=${result.signalDiagnostics.postsProcessed} detected=${result.signalDiagnostics.signalsDetected} filtered=${result.signalDiagnostics.signalsFiltered} used=${result.signalDiagnostics.signalsUsed}`);
      }
      if (result.narrativeOverlap?.overlapDetected) {
        console.log(`[MIv3-Route] NarrativeOverlap | duplicates=${result.narrativeOverlap.duplicateNarratives.length} penalty=${result.narrativeOverlap.saturationPenalty}`);
      }
      let freshnessMetadata = null;
      if (result.snapshotId) {
        try {
          const [snap] = await db.select().from(miSnapshots).where(eq33(miSnapshots.id, result.snapshotId)).limit(1);
          if (snap) {
            const { buildFreshnessMetadata: buildFreshnessMetadata2, logFreshnessTraceability: logFreshnessTraceability2 } = await Promise.resolve().then(() => (init_snapshot_trust(), snapshot_trust_exports));
            freshnessMetadata = buildFreshnessMetadata2(snap);
            logFreshnessTraceability2("MIv3-Analyze", snap, freshnessMetadata);
          }
        } catch (fmErr) {
          console.warn(`[MIv3-Route] Freshness metadata build failed for snapshot ${result.snapshotId}: ${fmErr.message}`);
        }
      }
      return res.json({
        success: true,
        ...result,
        freshnessMetadata
      });
    } catch (err) {
      console.error("[MIv3-Route] Error:", err.message);
      if (err.message.includes("ISOLATION VIOLATION")) {
        return res.status(403).json({ error: err.message });
      }
      return res.status(500).json({ error: err.message || "Market Intelligence V3 analysis failed" });
    }
  });
  app2.get("/api/ci/mi-v3/snapshot/:campaignId", requireCampaign, async (req, res) => {
    try {
      const accountId = req.query.accountId || "default";
      const campaignId = req.params.campaignId;
      const snapshots = await db.select().from(miSnapshots).where(and22(
        eq33(miSnapshots.accountId, accountId),
        eq33(miSnapshots.campaignId, campaignId),
        inArray9(miSnapshots.status, ["COMPLETE", "PARTIAL"])
      )).orderBy(desc23(miSnapshots.createdAt)).limit(1);
      if (snapshots.length === 0) {
        return res.json({ snapshot: null, engineState: "REFRESH_REQUIRED", message: "No snapshot available. Run analysis first." });
      }
      const snapshot = snapshots[0];
      const readiness = getEngineReadinessState(snapshot, campaignId, ENGINE_VERSION);
      const result = buildResultFromSnapshot(snapshot);
      return res.json({
        snapshot,
        ...result,
        engineState: readiness.state,
        engineDiagnostics: readiness.diagnostics,
        freshnessMetadata: readiness.freshnessMetadata || null
      });
    } catch (err) {
      return res.status(500).json({ error: err.message });
    }
  });
  app2.post("/api/ci/mi-v3/refresh", requireCampaign, async (req, res) => {
    try {
      enforceEngineWhitelist(req);
      validateEngineIsolation("MARKET_INTELLIGENCE_V3");
      const accountId = req.body.accountId || "default";
      const campaignId = req.body.campaignId;
      if (!campaignId) {
        return res.status(422).json({ error: "campaignId is required" });
      }
      console.log(`[MIv3-Route] POST /api/ci/mi-v3/refresh | manual refresh | campaignId=${campaignId}`);
      const goalMode = req.body.goalMode === "REACH_MODE" ? "REACH_MODE" : "STRATEGY_MODE";
      const result = await MarketIntelligenceV3.run("overview", accountId, campaignId, true, goalMode);
      return res.json({
        success: true,
        message: "Snapshot refreshed",
        ...result
      });
    } catch (err) {
      console.error("[MIv3-Route] Refresh error:", err.message);
      return res.status(500).json({ error: err.message });
    }
  });
  app2.get("/api/ci/mi-v3/history/:campaignId", requireCampaign, async (req, res) => {
    try {
      const accountId = req.query.accountId || "default";
      const campaignId = req.params.campaignId;
      const snapshots = await db.select().from(miSnapshots).where(and22(
        eq33(miSnapshots.accountId, accountId),
        eq33(miSnapshots.campaignId, campaignId),
        inArray9(miSnapshots.status, ["COMPLETE", "PARTIAL"])
      )).orderBy(desc23(miSnapshots.createdAt)).limit(20);
      return res.json({
        history: snapshots.map((s) => ({
          id: s.id,
          version: s.version,
          marketState: s.marketState,
          confidenceLevel: s.confidenceLevel,
          overallConfidence: s.overallConfidence,
          executionMode: s.executionMode,
          volatilityIndex: s.volatilityIndex,
          dataFreshnessDays: s.dataFreshnessDays,
          createdAt: s.createdAt
        }))
      });
    } catch (err) {
      return res.status(500).json({ error: err.message });
    }
  });
  app2.get("/api/ci/mi-v3/telemetry/:snapshotId", async (req, res) => {
    try {
      const snapshotId = req.params.snapshotId;
      const records = await db.select().from(miTelemetry).where(eq33(miTelemetry.snapshotId, snapshotId));
      const signals = await db.select().from(miSignalLogs).where(eq33(miSignalLogs.snapshotId, snapshotId));
      return res.json({ telemetry: records, signals });
    } catch (err) {
      return res.status(500).json({ error: err.message });
    }
  });
  app2.post("/api/ci/mi-v3/plan-write-attempt", (req, res) => {
    try {
      assertNoPlanWrites();
    } catch (err) {
      return res.status(403).json({ error: err.message });
    }
  });
  app2.post("/api/ci/mi-v3/orchestrator-attempt", (req, res) => {
    try {
      assertNoOrchestrator();
    } catch (err) {
      return res.status(403).json({ error: err.message });
    }
  });
  app2.post("/api/ci/mi-v3/autopilot-attempt", (req, res) => {
    try {
      assertNoAutopilot();
    } catch (err) {
      return res.status(403).json({ error: err.message });
    }
  });
  app2.post("/api/ci/mi-v3/fetch-job", requireCampaign, async (req, res) => {
    try {
      const accountId = req.body.accountId || "default";
      const campaignId = req.body.campaignId;
      if (!campaignId) {
        return res.status(400).json({ error: "campaignId is required" });
      }
      const jobId = await startFetchJob(accountId, campaignId);
      const status = await getFetchJobStatus(jobId);
      return res.json({ jobId, status: status?.status || "QUEUED", message: "Data collection job queued via Two-Speed system" });
    } catch (err) {
      console.error("[MIv3-Route] Fetch-job error:", err.message);
      if (err.message.includes("already in progress") || err.message.includes("DEDUP")) {
        return res.status(409).json({ error: err.message });
      }
      return res.status(500).json({ error: err.message });
    }
  });
  app2.post("/api/ci/mi-v3/fetch", requireCampaign, async (_req, res) => {
    return res.status(410).json({ error: "DEPRECATED: Batch fetch removed. Use POST /api/ci/mi-v3/fetch-job to trigger collection via the global job queue." });
  });
  app2.get("/api/ci/mi-v3/fetch-status/:jobId", async (req, res) => {
    try {
      const jobId = req.params.jobId;
      const status = await getFetchJobStatus(jobId);
      if (!status) {
        return res.status(404).json({ error: "Job not found" });
      }
      return res.json(status);
    } catch (err) {
      console.error("[MIv3-Route] Fetch status error:", err.message);
      return res.status(500).json({ error: err.message });
    }
  });
}

// server/market-intelligence-v3/admin-routes.ts
init_db();
init_schema();
import { eq as eq34, sql as sql23, desc as desc24, and as and23, gte as gte8 } from "drizzle-orm";
function registerAdminMarketRoutes(app2) {
  app2.get("/api/admin/market/overview", async (_req, res) => {
    try {
      const [competitorCount] = await db.select({ count: sql23`count(*)` }).from(ciCompetitors);
      const [activeCompetitorCount] = await db.select({ count: sql23`count(*)` }).from(ciCompetitors).where(eq34(ciCompetitors.isActive, true));
      const [postCount] = await db.select({ count: sql23`count(*)` }).from(ciCompetitorPosts);
      const [commentCount] = await db.select({ count: sql23`count(*)` }).from(ciCompetitorComments);
      const [snapshotCount] = await db.select({ count: sql23`count(*)` }).from(miSnapshots);
      const queueDiagnostics = await getQueueDiagnostics();
      const recentJobs = await db.select({
        id: miFetchJobs.id,
        accountId: miFetchJobs.accountId,
        campaignId: miFetchJobs.campaignId,
        status: miFetchJobs.status,
        collectionMode: miFetchJobs.collectionMode,
        dataStatus: miFetchJobs.dataStatus,
        totalPostsFetched: miFetchJobs.totalPostsFetched,
        totalCommentsFetched: miFetchJobs.totalCommentsFetched,
        competitorCount: miFetchJobs.competitorCount,
        createdAt: miFetchJobs.createdAt,
        completedAt: miFetchJobs.completedAt,
        error: miFetchJobs.error
      }).from(miFetchJobs).orderBy(desc24(miFetchJobs.createdAt)).limit(20);
      return res.json({
        inventory: {
          totalCompetitors: Number(competitorCount.count),
          activeCompetitors: Number(activeCompetitorCount.count),
          totalPosts: Number(postCount.count),
          totalComments: Number(commentCount.count),
          totalSnapshots: Number(snapshotCount.count)
        },
        queue: queueDiagnostics,
        recentJobs
      });
    } catch (err) {
      return res.status(500).json({ error: err.message });
    }
  });
  app2.get("/api/admin/market/competitors", async (_req, res) => {
    try {
      const competitors = await db.select({
        id: ciCompetitors.id,
        name: ciCompetitors.name,
        platform: ciCompetitors.platform,
        profileLink: ciCompetitors.profileLink,
        isActive: ciCompetitors.isActive,
        accountId: ciCompetitors.accountId,
        campaignId: ciCompetitors.campaignId,
        createdAt: ciCompetitors.createdAt,
        analysisLevel: ciCompetitors.analysisLevel,
        enrichmentStatus: ciCompetitors.enrichmentStatus,
        fetchMethod: ciCompetitors.fetchMethod,
        postsCollected: ciCompetitors.postsCollected,
        commentsCollected: ciCompetitors.commentsCollected,
        dataFreshnessDays: ciCompetitors.dataFreshnessDays,
        lastCheckedAt: ciCompetitors.lastCheckedAt
      }).from(ciCompetitors).orderBy(desc24(ciCompetitors.createdAt)).limit(100);
      const enriched = competitors.map((c) => ({
        ...c,
        postCount: c.postsCollected || 0,
        commentCount: c.commentsCollected || 0
      }));
      return res.json({ competitors: enriched });
    } catch (err) {
      return res.status(500).json({ error: err.message });
    }
  });
  app2.get("/api/admin/market/freshness", async (_req, res) => {
    try {
      const latestSnapshots = await db.select({
        accountId: miSnapshots.accountId,
        campaignId: miSnapshots.campaignId,
        dataStatus: miSnapshots.dataStatus,
        createdAt: miSnapshots.createdAt,
        competitorHash: miSnapshots.competitorHash
      }).from(miSnapshots).orderBy(desc24(miSnapshots.createdAt)).limit(50);
      const freshnessEntries = latestSnapshots.map((s) => {
        const ageMs = Date.now() - new Date(s.createdAt).getTime();
        const ageHours = Math.round(ageMs / 36e5 * 10) / 10;
        const isFresh = ageHours <= 24;
        return {
          accountId: s.accountId,
          campaignId: s.campaignId,
          dataStatus: s.dataStatus,
          ageHours,
          isFresh,
          createdAt: s.createdAt
        };
      });
      return res.json({ freshness: freshnessEntries });
    } catch (err) {
      return res.status(500).json({ error: err.message });
    }
  });
  app2.get("/api/admin/market/crawler-status", async (_req, res) => {
    try {
      const queueDiagnostics = await getQueueDiagnostics();
      const runningJobs = await db.select({
        id: miFetchJobs.id,
        accountId: miFetchJobs.accountId,
        campaignId: miFetchJobs.campaignId,
        collectionMode: miFetchJobs.collectionMode,
        totalPostsFetched: miFetchJobs.totalPostsFetched,
        totalCommentsFetched: miFetchJobs.totalCommentsFetched,
        competitorCount: miFetchJobs.competitorCount,
        createdAt: miFetchJobs.createdAt
      }).from(miFetchJobs).where(eq34(miFetchJobs.status, "RUNNING")).orderBy(desc24(miFetchJobs.createdAt));
      const queuedJobs = await db.select({
        id: miFetchJobs.id,
        accountId: miFetchJobs.accountId,
        campaignId: miFetchJobs.campaignId,
        createdAt: miFetchJobs.createdAt
      }).from(miFetchJobs).where(eq34(miFetchJobs.status, "QUEUED")).orderBy(miFetchJobs.createdAt);
      const last24h = new Date(Date.now() - 864e5);
      const [completedCount] = await db.select({ count: sql23`count(*)` }).from(miFetchJobs).where(and23(eq34(miFetchJobs.status, "COMPLETED"), gte8(miFetchJobs.completedAt, last24h)));
      const [failedCount] = await db.select({ count: sql23`count(*)` }).from(miFetchJobs).where(and23(eq34(miFetchJobs.status, "FAILED"), gte8(miFetchJobs.completedAt, last24h)));
      return res.json({
        queue: queueDiagnostics,
        running: runningJobs,
        queued: queuedJobs,
        last24h: {
          completed: Number(completedCount.count),
          failed: Number(failedCount.count)
        }
      });
    } catch (err) {
      return res.status(500).json({ error: err.message });
    }
  });
}

