function buildEngineCoverageReport(signals, requiredCategories) {
  const counts = {
    pain: 0,
    desire: 0,
    objection: 0,
    pattern: 0,
    root_cause: 0,
    psychological_driver: 0
  };
  for (const s of signals) {
    counts[s.category] = (counts[s.category] || 0) + 1;
  }
  const missingCategories = [];
  for (const cat of requiredCategories) {
    const min2 = MIN_SIGNALS_PER_CATEGORY[cat] || 1;
    if ((counts[cat] || 0) < min2) {
      missingCategories.push(cat);
    }
  }
  return {
    pains: counts.pain,
    desires: counts.desire,
    objections: counts.objection,
    patterns: counts.pattern,
    rootCauses: counts.root_cause,
    psychologicalDrivers: counts.psychological_driver,
    totalSignals: signals.length,
    coverageSufficient: signals.length >= 1 && missingCategories.length === 0,
    missingCategories
  };
}
function resolveSignalsForEngine(state, engineId) {
  const requiredCategories = ENGINE_SIGNAL_REQUIREMENTS[engineId] || [];
  const signals = state.governedSignals.filter(
    (s) => requiredCategories.includes(s.category)
  );
  const cleanSignals = [];
  let contaminatedCount = 0;
  for (const signal of signals) {
    const leakCheck = checkSignalLeakage(signal.text);
    if (!leakCheck.clean) {
      contaminatedCount++;
      console.warn(`[SGL] PRE_DISPATCH_BLOCK | engine=${engineId} | signal=${signal.signalId} | leaks=[${leakCheck.leaks.join(",")}]`);
      continue;
    }
    const cleanEvidence = [];
    for (const ev of signal.evidence) {
      const evCheck = checkSignalLeakage(ev);
      if (evCheck.clean) {
        cleanEvidence.push(ev);
      }
    }
    cleanSignals.push({ ...signal, evidence: cleanEvidence });
  }
  if (contaminatedCount > 0) {
    console.warn(`[SGL] PRE_DISPATCH_PURGE | engine=${engineId} | blocked=${contaminatedCount} contaminated signal(s)`);
  }
  const coverage = buildEngineCoverageReport(cleanSignals, requiredCategories);
  if (!coverage.coverageSufficient) {
    console.error(
      `[SGL] COVERAGE_BLOCKED | engine=${engineId} | signals=${cleanSignals.length} | missing=[${coverage.missingCategories.join(",")}] | required=[${requiredCategories.join(",")}] | ENGINE_DISPATCH_HALTED`
    );
    state.consumptionLog.push({
      engineId,
      signalsConsumed: [],
      coverageReport: coverage,
      timestamp: (/* @__PURE__ */ new Date()).toISOString()
    });
    return {
      signals: [],
      coverage,
      traceToken: state.traceToken,
      engineId,
      blocked: true,
      insufficientCategories: coverage.missingCategories
    };
  }
  const rankedSignals = [...cleanSignals].sort((a, b) => b.confidence - a.confidence);
  for (const signal of rankedSignals) {
    if (!signal.consumedBy.includes(engineId)) {
      signal.consumedBy.push(engineId);
    }
  }
  const consumption = {
    engineId,
    signalsConsumed: rankedSignals.map((s) => s.signalId),
    coverageReport: coverage,
    timestamp: (/* @__PURE__ */ new Date()).toISOString()
  };
  state.consumptionLog.push(consumption);
  console.log(
    `[SGL] RESOLVE | engine=${engineId} | raw=${signals.length} | clean=${cleanSignals.length} | purged=${contaminatedCount} | categories=[${requiredCategories.join(",")}] | sufficient=true | ranked=${rankedSignals.length}`
  );
  return {
    signals: rankedSignals,
    coverage,
    traceToken: state.traceToken,
    engineId,
    blocked: false,
    insufficientCategories: []
  };
}
function checkSignalLeakage(text2) {
  const leaks = [];
  for (const pattern of LEAKAGE_PATTERNS) {
    if (pattern.test(text2)) {
      leaks.push(pattern.source);
    }
  }
  if (isRawComment(text2)) {
    leaks.push("RAW_COMMENT_CONTAMINATION");
  }
  return { clean: leaks.length === 0, leaks };
}
function getGovernanceSummary(state) {
  return {
    version: SGL_VERSION,
    traceToken: state.traceToken,
    totalSignals: state.governedSignals.length,
    coverage: state.coverageReport,
    enginesServed: [...new Set(state.consumptionLog.map((c) => c.engineId))],
    consumptionLog: state.consumptionLog
  };
}

