      const hooks = (e.hookArchetypes || []).map((h) => typeof h === "string" ? h : h.type || h.name || "").join(" ");
      const frameworks = (e.narrativeFrameworks || []).map((n) => typeof n === "string" ? n : n.type || n.name || "").join(" ");
