  if (!trafficFlowing && contentGenerated > 0) {
    violations.push("FUNNEL_STARVED: Content exists but no traffic is flowing \u2014 funnel has zero input");
  }
  if (contentGenerated === 0) {
    violations.push("NO_CONTENT_GENERATED: Zero content pieces have been generated \u2014 funnel cannot activate");
  }
  if (contentScheduled === 0 && contentItems.length > 0) {
    violations.push("NO_CONTENT_SCHEDULED: Content exists but none is scheduled for distribution");
  }
  let funnelStatus = "PENDING";
  if (trafficFlowing && contentGenerated > 0) {
    funnelStatus = "ACTIVE";
  } else if (contentGenerated > 0 && !trafficFlowing) {
    funnelStatus = "STARVED";
  }
  return {
    valid: violations.length === 0,
    trafficFlowing,
    contentGenerated,
    contentScheduled,
    contentPublished: publishedCount,
    funnelStatus,
    violations
  };
