  const hasPersuasion = !!persuasion;
  const narrativeStability = (hasAwareness ? 0.5 : 0) + (hasPersuasion ? 0.5 : 0);
  if (narrativeStability < 0.5) advisories.push("Weak upstream stability: awareness or persuasion data missing");
  const validationConfidence = validation ? safeNumber5(validation.claimConfidenceScore, 0.5) : 0.5;
  const competitorValidity = clamp12(validationConfidence, 0, 1);
  const maturity = safeNumber5(audience.maturityIndex, 0.5);
  const marketMaturityConfidence = maturity > 0.1 ? clamp12(0.5 + maturity * 0.5, 0, 1) : 0.3;
  const overallReliability = signalDensity * 0.25 + signalDiversity * 0.2 + narrativeStability * 0.2 + competitorValidity * 0.2 + marketMaturityConfidence * 0.15;
  const isWeak = overallReliability < 0.45;
  if (isWeak) advisories.push(`Data reliability WEAK (${overallReliability.toFixed(2)}) \u2014 confidence scores capped`);
