async function getOrchestratorStatus(jobId) {
  const [job] = await db.select().from(orchestratorJobs).where(eq53(orchestratorJobs.id, jobId)).limit(1);
  if (!job) return null;
  return {
    id: job.id,
    status: job.status,
    campaignId: job.campaignId,
    planId: job.planId,
    durationMs: job.durationMs,
    error: job.error,
    sections: job.sectionStatuses ? JSON.parse(job.sectionStatuses) : [],
    createdAt: job.createdAt,
    completedAt: job.completedAt
  };
}
async function getLatestOrchestratorRun(accountId, campaignId) {
  const [job] = await db.select().from(orchestratorJobs).where(
    and40(
      eq53(orchestratorJobs.accountId, accountId),
      eq53(orchestratorJobs.campaignId, campaignId)
    )
  ).orderBy(desc38(orchestratorJobs.createdAt)).limit(1);
  return job || null;
}

