// server/execution-activation/routes.ts
function handleError(res, err) {
  if (err.message === "PLAN_NOT_FOUND") {
    return res.status(404).json({ success: false, error: "PLAN_NOT_FOUND", message: "Plan not found" });
  }
  res.status(500).json({ success: false, error: err.message });
}
function registerExecutionActivationRoutes(app2) {
  app2.get("/api/execution-activation/status/:planId", async (req, res) => {
    try {
      const { planId } = req.params;
      const status = await getActivationStatus(planId);
      res.json({ success: true, ...status });
    } catch (err) {
      handleError(res, err);
    }
  });
  app2.post("/api/execution-activation/activate/:planId", async (req, res) => {
    try {
      const { planId } = req.params;
      const result = await activateExecution(planId);
      const errorStatusMap = {
        PLAN_NOT_APPROVED: 409,
        EMERGENCY_STOPPED: 409,
        INVALID_STATE_TRANSITION: 409,
        CONTENT_QUEUE_VALIDATION_FAILED: 422,
        CONTENT_GENERATION_FAILED: 500
      };
      if (!result.success) {
        const status = errorStatusMap[result.error || ""] || 500;
        return res.status(status).json({ success: false, ...result });
      }
      res.json({ success: true, ...result });
    } catch (err) {
      handleError(res, err);
    }
  });
  app2.post("/api/execution-activation/retry/:planId", async (req, res) => {
    try {
      const { planId } = req.params;
      const status = await getActivationStatus(planId);
      if (status.executionStatus !== "ACTIVATION_FAILED" && status.executionStatus !== "FAILED") {
        return res.status(409).json({
          success: false,
          error: "INVALID_STATE_FOR_RETRY",
          message: `Retry only allowed from ACTIVATION_FAILED or FAILED states. Current: ${status.executionStatus}`
        });
      }
      const result = await activateExecution(planId);
      res.json({ success: result.success, ...result });
    } catch (err) {
      handleError(res, err);
    }
  });
  app2.get("/api/execution-activation/content-queue/:planId", async (req, res) => {
    try {
      const { planId } = req.params;
      const status = await getActivationStatus(planId);
      if (!status.contentQueue) {
        return res.json({
          success: true,
          empty: true,
          message: "No content queue exists for this plan",
          violations: ["NO_CONTENT_TO_DISTRIBUTE: Content queue is empty"]
        });
      }
      res.json({
        success: true,
        empty: false,
        ...status.contentQueue
      });
    } catch (err) {
      handleError(res, err);
    }
  });
  app2.post("/api/execution-activation/validate-funnel/:planId", async (req, res) => {
    try {
      const { planId } = req.params;
      const status = await getActivationStatus(planId);
      if (!status.funnelFeeding) {
        return res.json({
          success: true,
          funnelStatus: "PENDING",
          message: "No content exists to feed the funnel",
          violations: ["FUNNEL_NOT_INITIALIZED: No content pipeline exists"]
        });
      }
      res.json({
        success: true,
        ...status.funnelFeeding
      });
    } catch (err) {
      handleError(res, err);
    }
  });
  console.log("[ExecutionActivation] Routes registered: activate, retry, status, content-queue, validate-funnel");
}

// server/strategic-core/index.ts
function registerStrategicCoreRoutes(app2) {
  registerGateRoutes(app2);
  registerExtractionRoutes(app2);
  registerConfirmRoutes(app2);
  registerThinkingRoutes(app2);
  registerValidationRoutes(app2);
  registerOrchestratorRoutes(app2);
  registerExecutionRoutes(app2);
  registerExecutionActivationRoutes(app2);
}

