// server/agent/index.ts
init_summarizers();
var AgentOperator = class {
  async runWithStream(config, send) {
    const result = await runOrchestrator({
      ...config,
      onProgress: (evt) => {
        const summary = summarizeEngine(evt.engineId, evt.output, evt.status, evt.blockReason);
        send({
          type: "engine_progress",
          engineId: evt.engineId,
          engineName: evt.engineName,
          tier: evt.tier,
          status: evt.status,
          engineIndex: evt.engineIndex,
          totalEngines: evt.totalEngines,
          durationMs: evt.durationMs,
          summary,
          blockReason: evt.blockReason
        });
      }
    });
    send({
      type: "done",
      overallStatus: result.status,
      planId: result.planId,
      completedEngines: result.completedEngines,
      failedEngine: result.failedEngine,
      blockReason: result.blockReason,
      durationMs: result.durationMs
    });
  }
};

// server/agent/routes.ts
function registerAgentRoutes(app2) {
  app2.post("/api/agent/run-stream", async (req, res) => {
    try {
      const { campaignId } = req.body;
      if (!campaignId) {
        return res.status(400).json({ error: "campaignId is required" });
      }
      res.setHeader("Content-Type", "text/event-stream");
      res.setHeader("Cache-Control", "no-cache");
      res.setHeader("Connection", "keep-alive");
      res.setHeader("Access-Control-Allow-Origin", "*");
      res.flushHeaders();
      const send = (event) => {
        if (!res.writableEnded) {
          res.write(`data: ${JSON.stringify(event)}

`);
        }
      };
      send({ type: "started", campaignId, totalEngines: 15 });
      await new AgentOperator().runWithStream(
        { accountId: "default", campaignId: String(campaignId) },
        send
      );
      if (!res.writableEnded) res.end();
    } catch (error) {
      console.error("[AgentRoutes] run-stream error:", error.message);
      try {
        if (!res.writableEnded) {
          res.write(`data: ${JSON.stringify({ type: "error", error: error.message })}

`);
          res.end();
        }
      } catch {
      }
    }
  });
  console.log("[AgentRoutes] Routes registered: POST /api/agent/run-stream");
}

// server/replit_integrations/chat/routes.ts
import OpenAI2 from "openai";

// server/replit_integrations/chat/storage.ts
init_db();
init_schema();
import { eq as eq79, desc as desc60 } from "drizzle-orm";
var chatStorage = {
  async getConversation(id) {
    const [conversation] = await db.select().from(conversations).where(eq79(conversations.id, id));
    return conversation;
  },
  async getAllConversations() {
    return db.select().from(conversations).orderBy(desc60(conversations.createdAt));
  },
  async createConversation(title) {
    const [conversation] = await db.insert(conversations).values({ title }).returning();
    return conversation;
  },
  async deleteConversation(id) {
    await db.delete(messages).where(eq79(messages.conversationId, id));
    await db.delete(conversations).where(eq79(conversations.id, id));
  },
  async getMessagesByConversation(conversationId) {
    return db.select().from(messages).where(eq79(messages.conversationId, conversationId)).orderBy(messages.createdAt);
  },
  async createMessage(conversationId, role, content) {
    const [message] = await db.insert(messages).values({ conversationId, role, content }).returning();
    return message;
  }
};

// server/replit_integrations/chat/routes.ts
var openai = new OpenAI2({
  apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY,
  baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL
});
function registerChatRoutes(app2) {
  app2.get("/api/conversations", async (req, res) => {
    try {
      const conversations2 = await chatStorage.getAllConversations();
      res.json(conversations2);
    } catch (error) {
      console.error("Error fetching conversations:", error);
      res.status(500).json({ error: "Failed to fetch conversations" });
    }
  });
  app2.get("/api/conversations/:id", async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const conversation = await chatStorage.getConversation(id);
      if (!conversation) {
        return res.status(404).json({ error: "Conversation not found" });
      }
      const messages2 = await chatStorage.getMessagesByConversation(id);
      res.json({ ...conversation, messages: messages2 });
    } catch (error) {
      console.error("Error fetching conversation:", error);
      res.status(500).json({ error: "Failed to fetch conversation" });
    }
  });
  app2.post("/api/conversations", async (req, res) => {
    try {
      const { title } = req.body;
      const conversation = await chatStorage.createConversation(title || "New Chat");
      res.status(201).json(conversation);
    } catch (error) {
      console.error("Error creating conversation:", error);
      res.status(500).json({ error: "Failed to create conversation" });
    }
  });
  app2.delete("/api/conversations/:id", async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      await chatStorage.deleteConversation(id);
      res.status(204).send();
    } catch (error) {
      console.error("Error deleting conversation:", error);
      res.status(500).json({ error: "Failed to delete conversation" });
    }
  });
  app2.post("/api/conversations/:id/messages", async (req, res) => {
    try {
      const conversationId = parseInt(req.params.id);
      const { content, campaignId } = req.body;
      await chatStorage.createMessage(conversationId, "user", content);
      const messages2 = await chatStorage.getMessagesByConversation(conversationId);
      const chatMessages = messages2.map((m) => ({
        role: m.role,
        content: m.content
      }));
      let systemPrompt = "You are a helpful marketing AI assistant.";
      try {
        if (campaignId) {
          const context = await loadSystemContext("default", String(campaignId));
          systemPrompt = buildSystemPrompt(context);
        }
      } catch (err) {
        console.warn("[Chat] Failed to load system context:", err);
      }
      res.setHeader("Content-Type", "text/event-stream");
      res.setHeader("Cache-Control", "no-cache");
      res.setHeader("Connection", "keep-alive");
      const stream = await openai.chat.completions.create({
        model: "gpt-4.1-mini",
        messages: [
          { role: "system", content: systemPrompt },
          ...chatMessages
        ],
        stream: true,
        max_completion_tokens: 2048
      });
      let fullResponse = "";
      for await (const chunk of stream) {
        const content2 = chunk.choices[0]?.delta?.content || "";
        if (content2) {
          fullResponse += content2;
          res.write(`data: ${JSON.stringify({ content: content2 })}

`);
        }
      }
      await chatStorage.createMessage(conversationId, "assistant", fullResponse);
      res.write(`data: ${JSON.stringify({ done: true })}

`);
      res.end();
    } catch (error) {
      console.error("Error sending message:", error);
      if (res.headersSent) {
        res.write(`data: ${JSON.stringify({ error: "Failed to send message" })}

`);
        res.end();
      } else {
        res.status(500).json({ error: "Failed to send message" });
      }
    }
  });
}

