      const signedRequest = req.body.signed_request;
      if (!signedRequest) {
        return res.status(400).json({ error: "Missing signed_request" });
      }
      const META_APP_SECRET = process.env.META_APP_SECRET || "";
      const parts = signedRequest.split(".");
      if (parts.length !== 2) {
        return res.status(400).json({ error: "Invalid signed_request format" });
      }
      const encodedSig = parts[0];
      const payload = parts[1];
      const crypto10 = __require("crypto");
      const expectedSig = crypto10.createHmac("sha256", META_APP_SECRET).update(payload).digest("base64").replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
      if (encodedSig !== expectedSig) {
        return res.status(403).json({ error: "Invalid signature" });
      }
      const data = JSON.parse(
        Buffer.from(payload, "base64").toString("utf-8")
      );
      const userId = data.user_id;
      const confirmationCode = crypto10.randomBytes(16).toString("hex");
      const host = req.get("host") || "localhost:5000";
      const protocol = req.headers["x-forwarded-proto"] || req.protocol;
      const statusUrl = `${protocol}://${host}/api/meta/data-deletion-status?code=${confirmationCode}`;
